use std::collections::BTreeMap;

#[macro_export]
macro_rules! string_map {
    ($($key:expr => $value:expr),*) => {{
        let mut map = BTreeMap::new();
        $(
            map.insert($key.to_string(), $value.to_string());
        )*
        map
    }};
}

use std::collections::BTreeMap;

#[macro_export]
macro_rules! string_map {
    ($($key:expr => $value:expr),* $(,)?) => {{
        let mut map = BTreeMap::new();
        $(
            map.insert($key.to_string(), $value.to_string());
        )*
        map
    }};
}
